import{_ as i,o as n,c as t,ag as r}from"./chunks/framework.DXGyWiRo.js";const s="/images/lekt2303.jpg",l="/images/lekt2301.jpg",p="/images/lekt2302.jpg",a="/images/lekt2304.jpg",k=JSON.parse('{"title":"Lektion 23","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion23.md","filePath":"lektionen/lektion23.md"}'),u={name:"lektionen/lektion23.md"};function o(d,e,h,c,b,g){return n(),t("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-23" tabindex="-1">Lektion 23 <a class="header-anchor" href="#lektion-23" aria-label="Permalink to &quot;Lektion 23&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>23.1. Der Infinitiv (तुमुन्)</li><li>23.2. Bildung des Infinitiv (तुमुन्)</li><li>23.3. Der Infinitiv (तुमुन्) zu den bisher gelernten Wurzeln</li><li>23.4. Wortliste</li><li>23.5. Übung</li><li>23.6. Wiederholungsübung</li></ul><h2 id="_23-1-der-infinitiv-तुमुन्" tabindex="-1">23.1. Der Infinitiv (तुमुन्) <a class="header-anchor" href="#_23-1-der-infinitiv-तुमुन्" aria-label="Permalink to &quot;23.1. Der Infinitiv (तुमुन्)&quot;">​</a></h2><p>Will man in Sanskrit ausdrücken, dass eine Tätigkeit um einer anderen Tätigkeit willen geschieht (&quot;um zu&quot;), kann man für die Tätigkeit, um deren willen es geschieht, den Infinitiv (तुमुन्) verwenden. Der Infinitiv bezeichnet in erster Linie den Zweck oder die Absicht:</p><blockquote><p>रामो गुरुवचनं श्रोतुं गतः = &quot;Rāma ist gegangen, um die Rede des Meisters zu hören.&quot;</p></blockquote><p>Beachten Sie, dass der Infinitiv - mit einigen fest definierten Ausnahmen - nicht als Subjekt oder Objekt eines Verbs stehen kann:</p><blockquote><p>&quot;Er lernt tanzen&quot; darf man also nicht mit dem Infinitiv (&quot;tanzen&quot;) übersetzen, sondern muss ein Verbalnomen verwenden, z.B.: नर्तनमधीते (इ + अधि 2 Ā: &quot;lernen&quot;).</p></blockquote><p>Der Infinitiv wird auch verwendet mit Verben und Substantiven in der Bedeutung &quot;wünschen&quot; oder &quot;sich sehnen&quot;, wenn der Agens (कर्तृ) des Infinitivs und des Verbs identisch sind:</p><blockquote><p>रामो गुरुवचनं श्रोतुमिच्छति = &quot;Rāma wünscht, die Rede des Meisters zu hören.&quot;</p></blockquote><p>Der Infinitiv wird u.a. auch verwendet bei Verben in den Bedeutungen &quot;fähig sein&quot;, &quot;es gibt&quot;, &quot;wissen&quot;, &quot;beginnen&quot;:</p><blockquote><p>साधुरधर्मं कर्तुं न शक्नोति = &quot;Ein Heiliger kann kein Unrecht tun.&quot;<br> अस्ति भोक्तुमन्नम् = &quot;Es gibt Speise zu essen&quot; (भुज् 7: Ā: esssen, P: regieren)</p></blockquote><p>Der Infinitiv wird auch verwendet mit Wörtern in den Bedeutungen &quot;ausreichend&quot;, &quot;fähig&quot; und mit Substantiven in den Bedeutungen &quot;Fähigkeit&quot;, &quot;Kraft&quot;, &quot;Geschicklichkeit&quot;:</p><blockquote><p>अस्त्यग्नेर्विभवः सर्वं दग्धुम् = &quot;Feuer hat die Macht, alles zu verbrennen.&quot;</p></blockquote><p>Auch mit Wörtern in der Bedeutung &quot;Zeit&quot; kann der Infinitiv verwendet werden in Ausdrücken wie &quot;Es ist Zeit zu ...&quot;:</p><blockquote><p>कालो भोजनं सेवितुम् = &quot;Es ist Zeit, sich dem Essen zu widmen&quot; = &quot;Es ist Zeit zu essen&quot;</p></blockquote><p>Der Infinitiv kann aktivisch und passivisch verwendet werden. Ein passiver Infinitiv im Deutschen wird im Sanskrit dadurch wiedergegeben, dass das Verb (besonders häufig शक् &quot;fähig sein, können&quot;), von dem der Infinitiv abhängt, ins Passiv gesetzt wird.</p><p>Bezüglich des Objekts verhält sich der Infinitiv wie eine Verbalform, d.h. das direkte Objekt (कर्मन्) steht bei aktivisch gebrauchtem Infinitiv im Akkustaiv (द्वितीया), bzw. dem Kasus, den das betr. Verb verlangt ; bei passivisch gebrauchtem Infinitiv steht das direkte Objekt im Nominativ.</p><p>z.B.</p><blockquote><p>साधुरधर्मं कर्तुं न शक्नोति = साधुनाधर्मो कर्तुं न शक्यते = &quot;Ein Heiliger kann kein Unrecht tun.&quot;</p></blockquote><p>In der 2. Person wird अर्ह् + Infinitiv oft als milder Befehl verwendest: &quot;Du solltest&quot;.</p><p>Wenn der Infinitiv von einem Nomen abhängt, darf er mit diesem nicht zu einem Kompositum verbunden werden. Ausgenommen sind Bahuvrīhi, deren zweites Glied काम oder मनस् ist:</p><blockquote><p>वक्तुकामः = वक्तुं कामो यस्य सः = &quot;einer dessen Wunsch es ist, zu sprechen; einer, der zu sprechen wünscht&quot;.</p></blockquote><h2 id="_23-2-bildung-des-infinitiv-तुमुन्" tabindex="-1">23.2. Bildung des Infinitiv (तुमुन्) <a class="header-anchor" href="#_23-2-bildung-des-infinitiv-तुमुन्" aria-label="Permalink to &quot;23.2. Bildung des Infinitiv (तुमुन्)&quot;">​</a></h2><p>hochstufige Wurzel + -tum</p><p>bzw.</p><p>hochstufige Wurzel + -i- + -tum</p><p>Auslautende Konsonanten der Wurzel werden vor -tum nach denselben Regeln verändert wie vor dem -ta des PPP.</p><p>Verben mit Präverb bilden den Infinitiv in gleicher Weise wie die einfachen Wurzeln.</p><p>Beispiele:</p><blockquote><p>दिश् : देष्टुम्<br> रुद् : रोदितुम्</p></blockquote><p>Über die Verwendung des Bindevokals -i- lassen sich keine festen Regeln aufstellen. Im Wesentlichen stimmt die Verteilung des Bindevokals beim Infinitiv mit der des Futurs überein.</p><p>Zu den bisher gelernten Wurzeln sind folgende Infinitive besonders zu beachten:</p><blockquote><p>गम् : गन्तुम्</p><p>प्रच्छ् : प्रष्टुम्</p></blockquote><p>-ra- als Hochstufe zu -ṛ- haben im Infinitiv:</p><blockquote><p>दृश् : द्रष्टुम्</p><p>सृज् : स्रष्टुम्</p></blockquote><p>Die anderen Wurzeln mit -ṛ- an vorletzter Stelle haben fakultativ -ra- oder -ar-, wenn sie aniṭ sind.</p><h2 id="_23-3-der-infinitiv-तुमुन्-zu-den-bisher-gelernten-wurzeln" tabindex="-1">23.3. Der Infinitiv (तुमुन्) zu den bisher gelernten Wurzeln <a class="header-anchor" href="#_23-3-der-infinitiv-तुमुन्-zu-den-bisher-gelernten-wurzeln" aria-label="Permalink to &quot;23.3. Der Infinitiv (तुमुन्) zu den bisher gelernten Wurzeln&quot;">​</a></h2><p>अद् 2P अत्तुम्</p><p>अश् 5Ā अशितुम् । अष्टुम्</p><p>अस् 2P --</p><p>अस् 4P असितुम्</p><p>आप् 5P आप्तुम्</p><p>आस् 2Ā आसितुम्</p><p>इ 2P एतुम्</p><p>इष् 6P एष्टुम् । एषितुम्</p><p>कुप् 4P कोपितुम्</p><p>कृ 8U कर्तुम्</p><p>कृष् 1P कर्ष्टुम् । क्राष्टुम्</p><p>कृष् 6U कर्ष्टुम् । क्राष्टुम्</p><p>क्रुध् 4P कोद्धुम्</p><p>खाद् 1P खादितुम्</p><p>गम् 1P गन्तुम्</p><p>जन् 4Ā जनितुम्</p><p>जि 1P जेतुम्</p><p>जीव् 1P जीवितुम्</p><p>तन् 8U तनितुम्</p><p>दह् 1P दग्धुम्</p><p>दिश् 6U देष्टुम्</p><p>दुष् 4P --</p><p>दुह् 2U दोग्धुम्</p><p>दृश् द्रष्टुम्</p><p>द्विष् 2U द्वेष्टुम्</p><p>नी 1U नेतुम्</p><p>नृत् 4P नर्तितुम्</p><p>पच् 1U पक्तुम्</p><p>पद् 4Ā पत्तुम्</p><p>पा 1P पातुम्</p><p>पा 2P पातुम्</p><p>प्रच्छ् 6P प्रष्टुम्</p><p>बुध् 1U, 4Ā बोधितुम् । बोद्धुम्</p><p>ब्रू 2U --</p><p>भज् 1U भक्तुम्</p><p>भू 1P भवितुम्</p><p>मन् 4Ā मन्तुम्</p><p>मुच् 6U मोक्तुम्</p><p>मुह् 4P मोहितुम् । मोग्धुम् । मोढुम्</p><p>मृ 4Ā मर्तुम्</p><p>यज् 1U यष्टुम्</p><p>युध् 4Ā योद्धुम्</p><p>रक्ष् 1P रक्षितुम्</p><p>रुद् 2P रोदितुम्</p><p>लभ् 1Ā लब्धुम्</p><p>लुभ् 4P लोभितुम्</p><p>वच् 2P वक्तुम्</p><p>वद् 1P वदितुम्</p><p>विश् 6P वेष्टुम्</p><p>वृत् 1Ā वर्तितुम्</p><p>श्रु 5P श्रोतुम्</p><p>सद् 1P सत्तुम्</p><p>सह् 1Ā सहितुम् सोढुम्</p><p>सिच् 6U सेक्तुम्</p><p>सु 5U सोतुम्</p><p>सृज् 6P स्रष्टुम्</p><p>स्तु 2U स्तोतुम्</p><p>स्था 1P स्थातुम्</p><p>स्मृ 1P स्मर्तुम्</p><p>हन् 2P हन्तुम्</p><h2 id="_23-4-wortliste" tabindex="-1">23.4. Wortliste <a class="header-anchor" href="#_23-4-wortliste" aria-label="Permalink to &quot;23.4. Wortliste&quot;">​</a></h2><p>समान ३: gleich</p><p>सामान्य n.: Gleichheit, Übereinstimmung</p><p>अधिक ३ : überschüssig, zusätzlich, größer, besser, außerordentlich</p><p>विशेष m.: Besonderheit, Spezifikation, differentia specifica</p><h2 id="_23-5-ubung" tabindex="-1">23.5. Übung <a class="header-anchor" href="#_23-5-ubung" aria-label="Permalink to &quot;23.5. Übung&quot;">​</a></h2><p>A) Folgende Wurzeln bilden den Infinitiv ohne Bindevokal -i-. Bilden Sie den Infinitiv unter Beachtung der Lautveränderungen zu:</p><ol><li>आप्</li><li>इ</li><li>गम्</li><li>कृ</li><li>क्रुध्</li><li>जि</li><li>दुह्</li><li>दिश्</li><li>दह्</li><li>सृज्</li><li>द्विष्</li><li>नी</li><li>पद्</li><li>पा १</li><li>पा २</li><li>भज्</li><li>कृष्</li><li>सु</li><li>मन्</li><li>मुच्</li><li>मृ</li><li>यज्</li><li>युध्</li><li>वच्</li><li>विश्</li><li>श्रु</li><li>प्रच्छ्</li><li>सिच्</li><li>स्तु</li><li>स्था</li><li>स्मृ</li><li>हन्</li><li>लभ्</li><li>अद्</li><li>दृश्</li><li>पच्</li><li>सद्</li></ol><p>B) Folgende Wurzeln bilden den Infinitiv mit Bindevokal -i-. Bilden Sie den Infinitiv zu:</p><ol><li>आस्</li><li>नृत्</li><li>रक्ष्</li><li>रुद्</li><li>वद्</li><li>वृत्</li><li>कुप्</li></ol><p>C) Folgende Wurzeln wahlweise mit oder ohne Bindevokal:</p><ol><li>अश्</li><li>इष्</li><li>बुध्</li><li>मुह् (3 Formen!)</li><li>सह्</li></ol><p>D) Übersetzen Sie und lösen Sie die Komposita auf:</p><p>नराः स्वर्गं लब्धुं देवान्यज्ञ्नैर्यष्टुमिच्छन्ति ॥१॥</p><p>महापुण्यं कृत्वा गतपापजनेन नरकं गन्तुं न शक्यते ॥२॥</p><p>फलवन्ति पुण्यानीति सज्जनो ऽधर्मं कर्तुं नेच्छति ॥३॥</p><p><img src="'+s+'" alt=""><br> Abb.: फल्वन्ति पुण्यानीति ...<br> ทำบุญ = पुण्यकरणम्, Thailand = ประเทศไทย <br> [Bildquelle: Y-Not ?. -- <a href="http://www.flickr.com/photos/36716657@N00/519798246/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/36716657@N00/519798246/</a>. -- Zugriff am 2008-12-13. --  <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine Bearbeitung)]</p><p>सुगतो लोकान्मोक्तुमार्यसत्यान्युपदिशति ॥४॥</p><p><img src="'+l+'" alt=""><br> Abb.: सुगतो लोकान्मोक्तुमार्यसत्यान्युपदिशति<br> Chiang Mai, Thailand = เชียงใหม่, ประเทศไทย <br> [Bildquelle: Wikipedia. GNU FDLicense]</p><p>शूद्रजनो ब्राह्मणेन सहात्तुं नार्हति ॥५॥</p><p>लोभसम्पन्ननरा नृत्यन्तीं सम्पन्नरूपदासीं द्रष्टुं गताः ॥६॥</p><p>शूद्रया संगत्य ब्राह्मणो यष्टुं नार्हति ॥७॥</p><p>धर्मं श्रोतुकामा ब्राह्मणी सपुत्रा गुरुं द्रष्टुं महानगरं गता ॥८॥</p><p>C) Übersetzen Sie folgendes सुभाषितम्</p><p>आहारनिद्राभयमैथुनं च<br> सामान्यमेतत्पशुभिर्नराणाम् ।<br> धर्मे हि तेषा्मधिको विशेषो<br> धर्मेण हीनाः पशुभिः समानाः ॥</p><p>Erklärung: हीन ३: PPP zu हा 3: verlassen ; धर्मे = Lokativ sg. &quot;im ...&quot;</p><p><img src="'+p+'" alt=""><br> Abb.:<br> आहारनिद्राभयमैथुनं च<br> सामान्यमेतत्पशुभिर्नराणाम् ।</p><p>Chittorgarh = चित्तौडगढ</p><p>[Bildquelle: von zz77. -- <a href="http://www.flickr.com/photos/zz77/2256200876/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/zz77/2256200876/</a>. -- Zugriff am 2008-12-13. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><h2 id="_23-6-wiederholungsubung" tabindex="-1">23.6. Wiederholungsübung <a class="header-anchor" href="#_23-6-wiederholungsubung" aria-label="Permalink to &quot;23.6. Wiederholungsübung&quot;">​</a></h2><p>Bitte keine Hilfsmittel benutzen!</p><p>A) Übersetzen Sie ins Sanskrit:</p><p>1. Die fünf (पञ्च) &quot;Qualen&quot; sind: Unwissenheit, der falsche Glaube ans Ich, Zuneigung, Abneigung und Anhänglichkeit an den leib.</p><p>2. Wissen gibt es für Gehorsam gegenüber einem Lehrer oder für viel Geld oder im Austausch gegen Wissen. Eine vierte Art von Wissenserwerb gibt es nicht.</p><p>3. Ein Niedriger spricht, handelt aber nicht ; ein Guter sprich nicht, sondern handelt nur.</p><p>4. Die Hilfswissenschaften zum Veda sind: Aussprachelehre, Ritualistik, Grammatik, Bedeutungslehre, Metrik (छन्दस्) und Kalenderlehre.</p><p>5. Yoga ist das Stoppen der Tätigkeiten des Denkorgans.</p><p>6. Recht siegt, nicht Unrecht ; Wahrheit siegt, nicht Lüge ; Geduld siegt, nicht Zorn ; Gott siegt, nicht ein Gegengott. (Passiv)</p><p>7. Der &quot;Stock&quot; bewirkt Erwerb und sicheren Besitz von Philosophie, Veda und Ökonomie. Die Führung dieses Stocks ist Politik.</p><p><img src="'+a+'" alt=""><br> Abb.: दण्डनीतिः<br> Manmohan Singh = ਮਨਮੋਹਨ ਸਿੰਘ = मनमोहन सिंह, Prime Minister of India = भारत के प्रधानमन्त्री, seit 2004<br> [Bildquelle: Wikipedia, Public domain]</p><p>8. Gattin, Sohn und Sklave, diese drei (त्रयस्) sind gemäß der Überlieferung besitzlos. Wozu diese kommen, das gehört dem, dem diese (drei) gehören.</p><p>9. Mücken wünschen eine Wunde, Herrscher wünschen Besitz, Niedrige wünschen Streit, Gute wünschen Frieden.</p><p>10. Die spezifische Pflicht eines Brahmanen ist: Studium, Lehren, Opfern als Opferherr, Opfern im Auftrag, Geben und Empfangen ; die eines Kṣatriya ist: Studium, Opfern als Opferherr, Geben, Lebensunterhalt durch Waffen, Hüten der Wesen ; die eines Vaiśya: Studium, Opfern als Opferherr, Geben, Ackerbau, Viehhaltung und Handel ; die eines Śūdra: Gehorsam gegenüber den Zweimalgeborenen, Wirtschaftstätigkeit, Tätigkeit (कर्म) von Handwerkern und Schaustellern.</p><p>11. Abklärung des Bewusstseins geschieht aufgrund der meditativen Entfaltung von freundlichem Wohlwollen, Mitgefühl, Mitfreude und Gleichmut, die als Objekt Glück und Leid, Gutes und Böses haben.</p><p>12. Arme haben viele Söhne, obwohl sie sie nicht wünschen. Reiche haben keinen Sohn. Seltsam ist die Regung des Schicksals.</p><p>14. Wen erschlägt nicht ein Frauenkörper (वपुस् n.) mit schlanker Taille, breiten Hüften, roten Lippen, schwarzen Augen, gebogenem Nabel, aufrechten Brüsten.</p><p>B) Deklinieren Sie in allen Ihnen bekannten Kasus क्षत्रिया f.</p><p>C) Geben Sie die Stammformen (Bedeutung, Präsensklasse, Modus, 3. sg. Präs. Indikativ, 3. sg. Passiv, PPP, Absolutiva, Infinitiv) zu folgenden Verben:</p><p>१. सह्</p><p>२. पा (2x)</p><p>३. वच्</p><p>४. हन्</p>',151)])])}const f=i(u,[["render",o]]);export{k as __pageData,f as default};
